import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface Task {
  id: number;
  title: string;
  description: string;
  status: 'todo' | 'in-progress' | 'done';
  priority: 'low' | 'medium' | 'high';
  dueDate: string;
  assignee: string;
}

export default function TaskList() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockTasks: Task[] = [
      { id: 1, title: 'Design UI', description: 'Design new UI components', status: 'in-progress', priority: 'high', dueDate: '2026-06-15', assignee: 'John Doe' },
      { id: 2, title: 'Fix bugs', description: 'Fix reported bugs', status: 'todo', priority: 'medium', dueDate: '2026-06-20', assignee: 'Jane Smith' },
      { id: 3, title: 'Code review', description: 'Review pull requests', status: 'done', priority: 'low', dueDate: '2026-06-10', assignee: 'Bob Johnson' },
    ];
    
    setTasks(mockTasks);
    setLoading(false);
  }, []);

  const filteredTasks = tasks.filter(t => t.title.toLowerCase().includes(search.toLowerCase()));

  const getPriorityColor = (priority: string) => {
    const colors: Record<string, string> = {
      high: 'text-red-600',
      medium: 'text-yellow-600',
      low: 'text-green-600',
    };
    return colors[priority] || 'text-gray-600';
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      todo: 'bg-gray-100 text-gray-800',
      'in-progress': 'bg-blue-100 text-blue-800',
      done: 'bg-green-100 text-green-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  if (loading) return <div className="p-6">Loading...</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Tasks</h1>
        <Button>New Task</Button>
      </div>

      <Input placeholder="Search tasks..." value={search} onChange={(e) => setSearch(e.target.value)} className="max-w-md" />

      <div className="space-y-2">
        {filteredTasks.map(t => (
          <Link key={t.id} to={`/tasks/${t.id}`}>
            <div className="p-4 border rounded-lg hover:shadow-lg transition">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-semibold">{t.title}</h3>
                <div className="flex gap-2">
                  <span className={`px-2 py-1 rounded text-sm font-medium ${getStatusColor(t.status)}`}>
                    {t.status.replace('-', ' ').toUpperCase()}
                  </span>
                  <span className={`px-2 py-1 rounded text-sm font-medium ${getPriorityColor(t.priority)}`}>
                    {t.priority.toUpperCase()}
                  </span>
                </div>
              </div>
              <p className="text-gray-600 text-sm mb-2">{t.description}</p>
              <p className="text-xs text-gray-500">
                Assigned to {t.assignee} • Due {new Date(t.dueDate).toLocaleDateString()}
              </p>
            </div>
          </Link>
        ))}
      </div>

      {filteredTasks.length === 0 && (
        <div className="text-center py-8 text-gray-500">No tasks found</div>
      )}
    </div>
  );
}
